$(document).ready(function(){$(".elective-title").text("Electives/Specializations subjects");function hideAllElectiveContent(){$(".elective-tabcontent").hide()}
function showSelectedElectiveContent(selectedValue){if(selectedValue){$("#"+selectedValue).show()}}
function syncSemesterDropdowns(changedSemester,selectedValue){const semesterPairs={4:5,5:4,6:7,7:6};const pairedSemester=semesterPairs[changedSemester];if(!pairedSemester)return;const pairedValue=selectedValue.replace(`-${changedSemester}`,`-${pairedSemester}`);const pairedDropdown=$(`#electives-subject${pairedSemester}`);if(pairedDropdown.length&&pairedDropdown.val()!==pairedValue){pairedDropdown.val(pairedValue).trigger("change.select2")}}
function isSpecificElectivePage(){return window.location.pathname.match(/-honors-hrm-mahe|-muj-mathematics-elective|-muj-econometrics-elective|-muj-data-science-elective|-muj-computational-science-elective|-honors-fintech-mahe|-honors-marketing-management-mahe|-honors-business-analytics-mahe|-honors-healthcare-management-mahe|-marketing|-finance-and-accounting|-healthcare-management-|-logistics-supply-chain-management-|-finance-|-hrm|-systems-|-ops-|-hc-|-data-and-analytics-|-cloud-computing-|-cyber-security-|-entrepreneurship-management-and-family-business|-bba-data-analytics|-bca-data-science-and-analytics|-retail-and-ecommerce|-digital-marketing|-artificial-intelligence-machine-learning-|-full-stack-development-|comprehensive-emerging-technologies|-mba-data-science-|-operations-management-|-pharmaceutical-management-|-cybersecurity-|-hr-|-operations-and-scm-|-healthcare-|-ai-and-data-science-|-ai-and-machine-learning-|-marketing-lp|-entrepreneurship-family-business-management-lp|-retail-ecommerce-lp|-accounting-with-ai-|-banking-and-fintech-|-ecommerce-|-accounting-and-taxation-|-economics-|-financial-analytics-|-digital-marketing-with-ai-|-business-analytics-|online-bba-entrepreneurship-smu|online-bba-operations-scm-smu|online-bba-banking-insurance-smu|/i)}
function getSpecificElective(){const path=window.location.pathname;if(path.match(/-honors-hrm-mahe/i))return"elec-hrm";if(path.match(/-muj-mathematics-elective/i))return"elec-math";if(path.match(/-muj-econometrics-elective/i))return"elec-econom";if(path.match(/-muj-data-science-elective/i))return"elec-ds";if(path.match(/-muj-computational-science-elective/i))return"elec-com";if(path.match(/-honors-fintech-mahe/i))return"elec-fintech";if(path.match(/-honors-marketing-management-mahe/i))return"elec-marketing";if(path.match(/-honors-business-analytics-mahe/i))return"elec-ba";if(path.match(/-honors-healthcare-management-mahe/i))return"elec-healthcare";if(path.match(/-digital-marketing/i))return"elec-dm";if(path.match(/-logistics-supply-chain-management-/i))return"elec-lscm";if(path.match(/-marketing/i))return"elec-marketing";if(path.match(/-marketing-lp/i))return"elec-marketing";if(path.match(/-entrepreneurship-family-business-management-lp/i))return"elec-emfc";if(path.match(/-finance-and-accounting/i))return"elec-fa";if(path.match(/-retail-ecommerce-lp/i))return"elec-ecommerce";if(path.match(/-finance-/i))return"elec-finance";if(path.match(/-hrm/i))return"elec-hrm";if(path.match(/-systems-/i))return"elec-systems";if(path.match(/-ops-/i))return"elec-ops";if(path.match(/-healthcare-management-/i))return"elec-hc";if(path.match(/-hc-/i))return"elec-hc";if(path.match(/-data-and-analytics-/i))return"elec-ds";if(path.match(/-cloud-computing-/i))return"elec-cc";if(path.match(/-cyber-security-/i))return"elec-cs";if(path.match(/-entrepreneurship-management-and-family-business/i))
return"elec-emfc";if(path.match(/-bba-data-analytics/i))return"elec-analysis";if(path.match(/-bca-data-science-and-analytics/i))
return"elec-ds";if(path.match(/-retail-and-ecommerce/i))return"elec-ecommerce";if(path.match(/-artificial-intelligence-machine-learning-/i))return"elec-aiml";if(path.match(/-full-stack-development-/i))return"elec-fsd";if(path.match(/comprehensive-emerging-technologies-/i))return"elec-gen";if(path.match(/-mba-data-science-/i))return"elec-ds";if(path.match(/-operations-management-/i))return"elec-om";if(path.match(/-pharmaceutical-management-/i))return"elec-pam";if(path.match(/-cybersecurity-/i))return"elec-cyber";if(path.match(/-hr-/i))return"elec-hrm";if(path.match(/-operations-and-scm-/i))return"elec-ops";if(path.match(/-healthcare-/i))return"elec-hc";if(path.match(/-ai-and-data-science-/i))return"elec-ai";if(path.match(/-ai-and-machine-learning-/i))return"elec-ai-and-mi";if(path.match(/-accounting-with-ai-/i))return"elec-aai";if(path.match(/-banking-and-fintech-/i))return"elec-fintech";if(path.match(/-business-analytics-/i))return"elec-analytics";if(path.match(/-ecommerce-/i))return"elec-ecom";if(path.match(/-accounting-and-taxation-/i))return"elec-at";if(path.match(/-economics-/i))return"elec-eco";if(path.match(/-financial-analytics-/i))return"elec-fa";if(path.match(/-digital-marketing-with-ai-/i))return"elec-dmai";if(path.match(/online-bba-entrepreneurship-smu/i))return"elec-entp";if(path.match(/online-bba-operations-scm-smu/i))return"elec-ops";if(path.match(/online-bba-banking-insurance-smu/i))return"elec-bi";return null}
function initializeSemesterDropdown(semester){const dropdown=$(`#electives-subject${semester}`);if(!dropdown.length)return;dropdown.on("change",function(){const selectedValue=$(this).val();hideAllElectiveContent();if(selectedValue){const semesterNumber=parseInt(selectedValue.split("-").pop());syncSemesterDropdowns(semesterNumber,selectedValue);showSelectedElectiveContent(selectedValue)}});if(!isSpecificElectivePage()){const firstOption=dropdown.find("option:eq(1)").val();if(firstOption){dropdown.val(firstOption).trigger("change.select2")}}}
if(isSpecificElectivePage()){const specificElective=getSpecificElective();if(specificElective){hideAllElectiveContent();[4,5,6,7].forEach((semester)=>{const dropdown=$(`#electives-subject${semester}`);if(dropdown.length){const value=`${specificElective}-${semester}`;dropdown.val(value).prop("disabled",!0).trigger("change.select2");showSelectedElectiveContent(value)}});$(".electives-layout").hide()}}else{[4,5,6,7].forEach(initializeSemesterDropdown);[4,6].forEach((semester)=>{const dropdown=$(`#electives-subject${semester}`);if(dropdown.length){const firstOption=dropdown.find("option:eq(1)").val();if(firstOption){dropdown.val(firstOption).trigger("change.select2")}}})}
if($('#yr1 .semester-block .elective-title').length>1){$('.elective-title').eq(1).hide();$('.elective-title').eq(3).hide()}
$(`.course-curriculum-sect .accordion `).click(function(){let index=$('.accordion').index(this);if(index===2||index===3){$('.elective-title').eq(1).hide();$('.elective-title').eq(3).hide()}})})